 hindiName: 'महाराजा जगत सिंह द्वितीय',
 title: 'जयपुर के महाराजा',
 period: '1803-1818 CE',
 image: '/images/dynasties/rulers/Maharaja_Sawai_Jagat_Singh_Maharaja_of_Jaipur.jpg',
 significance: 'Maintained administration in early 19th century Jaipur',
